package work

import (
	"context"
	"sync"
	"time"
)

type heartbeatStore interface {
	TouchClaimHeartbeat(string) error
}

// WithHeartbeat runs fn while periodically calling store.TouchClaimHeartbeat
// on a background goroutine at the given interval. The goroutine is stopped
// and waited for before WithHeartbeat returns.
func WithHeartbeat[T any](ctx context.Context, beadID string, interval time.Duration, store heartbeatStore, fn func() (T, error)) (T, error) {
	ticker := time.NewTicker(interval)
	defer ticker.Stop()
	return withHeartbeatCh(ctx, beadID, ticker.C, store, fn)
}

// withHeartbeatCh is the injectable variant used by tests to supply a stub tick channel.
func withHeartbeatCh[T any](ctx context.Context, beadID string, tickCh <-chan time.Time, store heartbeatStore, fn func() (T, error)) (T, error) {
	hbCtx, hbCancel := context.WithCancel(ctx)
	var wg sync.WaitGroup
	wg.Add(1)
	go func() {
		defer wg.Done()
		for {
			select {
			case <-hbCtx.Done():
				return
			case <-tickCh:
				_ = store.TouchClaimHeartbeat(beadID)
			}
		}
	}()
	result, err := fn()
	hbCancel()
	wg.Wait()
	return result, err
}

package work

import (
	"context"
	"errors"
	"sync/atomic"
	"testing"
	"time"
)

type stubHeartbeatStore struct {
	count atomic.Int32
}

func (s *stubHeartbeatStore) TouchClaimHeartbeat(_ string) error {
	s.count.Add(1)
	return nil
}

func TestWithHeartbeat_TickerFiredBeforeReturn(t *testing.T) {
	store := &stubHeartbeatStore{}
	tickCh := make(chan time.Time, 1)
	tickCh <- time.Now()

	_, err := withHeartbeatCh(context.Background(), "bead-1", tickCh, store, func() (struct{}, error) {
		time.Sleep(10 * time.Millisecond)
		return struct{}{}, nil
	})

	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if store.count.Load() < 1 {
		t.Errorf("expected Heartbeat called at least once, got %d", store.count.Load())
	}
}

func TestWithHeartbeat_CancelPropagates(t *testing.T) {
	store := &stubHeartbeatStore{}
	ctx, cancel := context.WithCancel(context.Background())
	tickCh := make(chan time.Time) // unbuffered; no ticks will be sent

	done := make(chan struct{})
	go func() {
		defer close(done)
		_, _ = withHeartbeatCh(ctx, "bead-1", tickCh, store, func() (struct{}, error) {
			cancel()
			return struct{}{}, errors.New("fn error")
		})
	}()

	select {
	case <-done:
	case <-time.After(1 * time.Second):
		t.Fatal("withHeartbeatCh did not return after context cancellation")
	}
}

